solution:
#[derive(Debug)]
struct ColorTupleStruct(i32, i32, i32);

#[derive(Debug)]
struct UnitStruct;

fn main() {
    let green = ColorTupleStruct(0, 255, 0);

    assert_eq!(green.0, 0);
    assert_eq!(green.1, 255);
    assert_eq!(green.2, 0);

    let unit = UnitStruct;
    let message = format!("{:?}", unit);
    println!("Tuple struct green.1 = {}", green.1);
}
